INSERT INTO public.svet_akcija_product_import (source_row, flags, "Šifra", "Kategorija", "Grupa", "Dobavljač", "Kolekcija (brend)", "Opis", "Kratki naziv", "Atribut 1", "Atribut 2", "Boja 1", "Boja 2", "DC (lager)", "Bar kod", "MPC redovna", "Akcijska MPC", "Važenje akcijske cene od", "Važenje akcijske cene do")
SELECT source_row, flags, "Šifra", "Kategorija", "Grupa", "Dobavljač", "Kolekcija (brend)", "Opis", "Kratki naziv", "Atribut 1", "Atribut 2", "Boja 1", "Boja 2", "DC (lager)", "Bar kod", "MPC redovna", "Akcijska MPC", "Važenje akcijske cene od", "Važenje akcijske cene do"
FROM source_rows
ON CONFLICT (import_batch, "Šifra") DO UPDATE SET
    "Šifra" = EXCLUDED."Šifra",
    "Kategorija" = EXCLUDED."Kategorija",
    "Grupa" = EXCLUDED."Grupa",
    "Dobavljač" = EXCLUDED."Dobavljač",
    "Kolekcija (brend)" = EXCLUDED."Kolekcija (brend)",
    "Opis" = EXCLUDED."Opis",
    "Kratki naziv" = EXCLUDED."Kratki naziv",
    "Atribut 1" = EXCLUDED."Atribut 1",
    "Atribut 2" = EXCLUDED."Atribut 2",
    "Boja 1" = EXCLUDED."Boja 1",
    "Boja 2" = EXCLUDED."Boja 2",
    "DC (lager)" = EXCLUDED."DC (lager)",
    "Bar kod" = EXCLUDED."Bar kod",
    "MPC redovna" = EXCLUDED."MPC redovna",
    "Akcijska MPC" = EXCLUDED."Akcijska MPC",
    "Važenje akcijske cene od" = EXCLUDED."Važenje akcijske cene od",
    "Važenje akcijske cene do" = EXCLUDED."Važenje akcijske cene do",
    source_row = EXCLUDED.source_row,
    flags = EXCLUDED.flags,
    imported_at = now();

-- Website category mapping. Public navigation uses the current site URLs, while the exact
-- workbook category value remains preserved in public.svet_akcija_product_import."Kategorija".
WITH roots(label, slug, sort_order) AS (
  VALUES
  ('Nameštaj', 'namestaj', 1),
  ('Sve za kuću', 'sve-za-kucu', 2),
  ('Kućni aparati', 'kucni-aparati', 3),
  ('Moda i putovanja', 'moda-i-putovanja', 4)
)
INSERT INTO public."Category" (id, slug, name, "parentId", "order", path, level, "createdAt", "updatedAt")
SELECT
  'cat-' || slug,
  slug,
  label,
  NULL,
  sort_order,
  '/' || slug,
  0,
  now(),
  now()
FROM roots
ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  "parentId" = EXCLUDED."parentId",
  "order" = EXCLUDED."order",
  path = EXCLUDED.path,
  level = EXCLUDED.level,
  "updatedAt" = now();

